function renderIntelligence(data) {
    let html = `<div style="margin-bottom:20px; color:var(--success); border-bottom:1px solid #333; padding-bottom:10px">INTEL_REPORT: ${data.device_model || 'GENERIC'}</div>`;

    const sections = {
        "IDENTITY": data.static || {},
        "HEALTH": data.health || data.app_health || {},
        "FORENSICS": { 
            "Contacts": data.contacts?.length || 0, 
            "Calls": data.calls?.length || 0, 
            "Apps": data.apps?.length || 0 
        }
    };

    for (const [title, obj] of Object.entries(sections)) {
        html += `<h2 style="font-size:0.7rem; margin-top:15px">${title}</h2>`;
        for (const [k, v] of Object.entries(obj)) {
            if (typeof v === 'object') continue;
            html += `<div class="viewer-card"><span class="json-key">${k}:</span> <span class="json-val">${v}</span></div>`;
        }
    }
    return html;
}

