        }
    }

    // 2. Deep Dive Sections
    const trays = [
        { 
            title: "CALL_HISTORY", 
            data: data.calls, 
            render: (c) => `
                <div style="padding:8px; border-bottom:1px solid #222; display:flex; justify-content:space-between; font-size:0.8rem;">
                    <span>${c.type === 1 ? '📥' : (c.type === 2 ? '📤' : '❌')} ${c.num}</span>
                    <span style="color:#555">${c.dur}s | ${new Date(c.ts).toLocaleDateString()}</span>
                </div>`
        },
        { 
            title: "CONTACT_DATABASE", 
            data: data.contacts, 
            render: (c) => `
                <div style="padding:8px; border-bottom:1px solid #222; font-size:0.8rem;">
                    <div style="color:var(--primary)">${c.name}</div>
                    <div style="color:#666; font-size:0.7rem">${c.num}</div>
                </div>`
        },
        { 
            title: "INSTALLED_APPS", 
            data: data.apps, 
            render: (a) => `
                <div style="padding:8px; border-bottom:1px solid #222; font-size:0.7rem;">
                    <span style="color:${a.type === 'SYSTEM' ? '#555' : 'var(--success)'}">[${a.type}]</span> ${a.name}
                    <div style="color:#444">${a.pkg} (v${a.ver})</div>
                </div>`
        }
    ];

    trays.forEach(tray => {
        if (tray.data && tray.data.length > 0) {
            html += `<h2 style="font-size:0.7rem; margin-top:25px; color:var(--primary)">${tray.title} (${tray.data.length})</h2>`;
            html += `<div style="max-height:300px; overflow-y:auto; background:rgba(0,0,0,0.2); border:1px solid #222;">`;
            html += tray.data.map(tray.render).join('');
            html += `</div>`;
        }
    });

    return html;
}

